    ArrayList<String> list = new ArrayList<>();
    list.add("Алиса");
    list.add("Боб");
    list.add("Алиса");
    System.out.println("List: " + list);

    // Пример Set
    HashSet<String> set = new HashSet<>();
    set.add("Алиса");
    set.add("Боб");
    set.add("Алиса");
    System.out.println("Set: " + set);

    // Пример Map
    HashMap<Integer, String> map = new HashMap<>();
    map.put(1, "Алиса");
    map.put(2, "Боб");
